TRUNCATE TABLE public.attendance_records, public.sessions, public.enrollments, public.courses, public.users CASCADE;







SELECT setval('public.users_id_seq', (SELECT MAX(id) FROM public.users));
SELECT setval('public.courses_id_seq', (SELECT MAX(id) FROM public.courses));
SELECT setval('public.sessions_id_seq', (SELECT MAX(id) FROM public.sessions));